+        fn rearm_wake_poll(&self) -> io::Result<()> {
+            let mut ring = self.ring.lock();
+            if let Err(err) = submit_poll_entry(
+                &mut ring,
+                self.wake_fd.as_raw_fd(),
+                Interest::READABLE,
+                WAKE_USER_DATA,
+            ) {
+                if err.kind() != io::ErrorKind::WouldBlock {
+                    return Err(err);
+                }
+                ring.submit()?;
+                submit_poll_entry(
+                    &mut ring,
+                    self.wake_fd.as_raw_fd(),
+                    Interest::READABLE,
+                    WAKE_USER_DATA,
+                )?;
+            }
+            ring.submit()?;
+            Ok(())
+        }
     }

